<div class="content-wrapper"><section class="content-header"><h1>Manage Issues</h1></section><section class="content">
<button class="btn btn-primary" data-toggle="modal" data-target="#issueModal">Add Issue</button><br><br>
<div class="box"><div class="box-body table-responsive"><table class="table table-bordered"><thead><tr><th>Issue Title</th><th>Volume</th><th>Issue</th><th>Year</th><th>Status</th><th>Action</th></tr></thead><tbody>
<?php foreach(($issues ?? []) as $i): ?><tr><td><?= !empty($i->title) ? html_escape($i->title) : '-' ?></td><td><?= (int)$i->volume ?></td><td><?= (int)$i->issueNumber ?></td><td><?= (int)$i->year ?></td><td><span class="label label-<?= ($i->status ?? 'draft') === 'published' ? 'success' : 'default' ?>"><?= html_escape(ucfirst($i->status ?? 'draft')) ?></span></td><td><button class="btn btn-xs btn-info" data-toggle="modal" data-target="#issueModal" onclick="setIssue(<?= (int)$i->issueId ?>,<?= (int)$i->volume ?>,<?= (int)$i->issueNumber ?>,<?= (int)$i->year ?>,'<?= html_escape($i->month) ?>','<?= html_escape($i->title ?? '') ?>','<?= html_escape($i->status ?? 'draft') ?>')">Edit</button> <a class="btn btn-xs btn-danger" href="<?= base_url('publisher/issues/delete/' . (int)$i->issueId) ?>" onclick="return confirm('Delete this issue?')">Delete</a></td></tr><?php endforeach; ?>
</tbody></table></div></div>
<div class="modal fade" id="issueModal"><div class="modal-dialog"><div class="modal-content"><form method="post" action="<?= base_url('publisher/issues/save') ?>"><div class="modal-header"><button type="button" class="close" data-dismiss="modal">&times;</button><h4>Add/Edit Issue</h4></div><div class="modal-body"><input type="hidden" name="issueId" id="issueId"><input class="form-control" name="title" id="title" placeholder="Issue Title" required><br><input class="form-control" name="volume" id="volume" placeholder="Volume" required><br><input class="form-control" name="issueNumber" id="issueNumber" placeholder="Issue Number" required><br><input class="form-control" name="year" id="year" placeholder="Year" required><br><input class="form-control" name="month" id="month" placeholder="Month"><br><select class="form-control" name="status" id="status" required><option value="draft">Draft</option><option value="published">Published</option></select></div><div class="modal-footer"><button class="btn btn-primary">Save</button></div></form></div></div></div>
</section></div><script>function setIssue(id,v,i,y,m,t,s){document.getElementById('issueId').value=id;document.getElementById('volume').value=v;document.getElementById('issueNumber').value=i;document.getElementById('year').value=y;document.getElementById('month').value=m;document.getElementById('title').value=t||'';document.getElementById('status').value=s||'draft';}</script>
